  ('heelevel3-d0d1b9a2-moex-00265', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲公司之部分成本資料包含：期初直接材料存貨$100、期末直接材料存貨$70、期初在製品存貨 $500、期末在製品存貨$600、直接製造人工$110、製造費用合計$80、製成品成本$210。下列何者 為直接材料之購入金額？', '["$10", "$90", "$120", "$150"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "38de3451dea6", "answer_pdf_sha1": "8d5212a0471e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00266', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲公司有聯產品A，其數量為200單位，可選擇在分離點時出售，或選擇繼續加工再投入成本 $8,000，最終以每單位$120出售。當繼續加工與否無差異時，下列何者為A產品在分離點的價格？', '["$80", "$90", "$105", "$120"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "38de3451dea6", "answer_pdf_sha1": "8d5212a0471e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00267', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲部門在月初將500單位完工品轉入乙部門繼續加工。乙部門另加入材料成本$6,750、加工成本 $9,500。月底乙部門尚有在製品50單位，完工程度為材料100%、加工成本50%。下列何者為加工 成本之約當單位成本？', '["$5", "$10", "$15", "$20"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "38de3451dea6", "answer_pdf_sha1": "8d5212a0471e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00268', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲食品公司A部門採分步成本制度，材料於生產開始時就全部投入，加工成本則於生產過程中均 勻投入。本期期初在製品1,000單位，期初在製品成本中之加工成本為$13,600，完工程度為20%； 完工轉到次部門3,000單位，期末在製品800單位，完工程度為50%，本期投入加工成本$326,400， 當月份並未出現任何損壞單位，在先進先出法下，下列何者最接近加工成本之約當單位成本？', '["$96.50", "$100.75", "$102.00", "$106.25"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "38de3451dea6", "answer_pdf_sha1": "8d5212a0471e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00269', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '有關分批成本制之非常損壞成本處理之敘述，下列何者正確？', '["列為當期損失", "列為當期完好產品之成本", "列為該特定批次產品之成本", "列為所有批次產品之成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "38de3451dea6", "answer_pdf_sha1": "8d5212a0471e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00270', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '傳統成本會計制度對製造業的會計處理，基本上可分為以下四個階段：購買生產要素（階段1）、 投入生產要素（階段2）、產品完工（階段3）、銷售產品（階段4）。如採倒推成本法並省略階段2時， 下列何者不會出現在階段3之會計分錄中？', '["借：製成品", "貸：材料及在製品", "貸：在製品", "貸：已分攤加工成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "38de3451dea6", "answer_pdf_sha1": "8d5212a0471e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00271', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '丙公司採用分批成本制，該公司於六月發生$17,000的損壞品，並由管理當局認定為非常損壞，且 追蹤其發生的原因是來自批次#888的訂單，該訂單於三個月後以$459,000售出。有關該損壞對丙 公司在批次#888訂單的單位生產成本和公司整體營業淨利的影響，下列敘述何者正確？ 單位生產成本 營業淨利', '["增加 沒有影響", "增加 減少", "沒有影響 減少", "沒有影響 資料不足無法判斷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "38de3451dea6", "answer_pdf_sha1": "8d5212a0471e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00272', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲公司預估X1年各季之銷售量如下： 季 1 2 3 4 銷售量 7,000單位 8,000單位 10,000單位 6,000單位 甲公司之存貨政策為：製成品之期末存貨量為下一季銷售量的10%，直接材料之期末存貨量為下 一季用量的20%。甲公司每生產一單位產品需耗用2公斤之直接原料，下列何者為甲公司第2季直 接原料預計採購量？', '["15,840公斤", "16,640公斤", "16,960公斤", "17,200公斤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "38de3451dea6", "answer_pdf_sha1": "8d5212a0471e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00273', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '乙公司銷售行動電源，產品單位售價$480，單位變動成本$450；固定成本則包括廠房租金$250,000， 銷售費用$300,000，折舊費用$100,000，以及管理費用$150,000。下列何者為銷售量40,000單位時 的營業槓桿度？', '["0.33", "0.50", "2.00", "3.00"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:00+00:00", "source_pdf_sha1": "38de3451dea6", "answer_pdf_sha1": "8d5212a0471e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
